export const getGetRecentSignalsUrl = (params?: GetRecentSignalsParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/dashboard/signals?${stringifiedParams}` : `/api/v1/dashboard/signals`
}

/**
 * @summary Get recent signal feed
 */
